solution.code:
def solution(n: int = 100) -> int:
    # Use a set to automatically handle and remove duplicate values
    results = set()
    # Ensure the range includes the limit n by using n + 1
    for a in range(2, n + 1):
        for b in range(2, n + 1):
            results.add(a**b)
    return len(results)


if __name__ == "__main__":
    print(solution(100))
